#include <bits/stdc++.h>
using namespace std;
int a[50];
int main(){
	string s;
	int top=0;
	getline(cin,s);
	for(int i=0;i<s.size();i++){
		if(s[i]=='(')
			a[++top]=1;
		else if(s[i]==')'){
			if(a[top]==1)top--;
			else{
				cout<<"NO";
				return 0;
			}
		}
	}
	if(top)cout<<"NO";
	else cout<<"YES";
	return 0;
}
